<?php

use Admin_Model_OrderStateType as OrderStateType;
use common\logic\Email\EmailFactory;
use user\logic\UserAdminSession;

/**
 * Admin_Model_OrderState
 *
 * This class has been auto-generated by the Doctrine ORM Framework
 *
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
 * @author     ##NAME## <##EMAIL##>
 * @version    SVN: $Id: Builder.php 7490 2010-03-29 19:53:27Z jwage $
 */
class Admin_Model_OrderState extends Admin_Model_Base_OrderState {

    const USER_BALIKOBOT = "Balikobot";
    const USER_GOPAY = "GoPay";
    const USER_CSOB = 'ČSOB';

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        $isNew = $this->ID == null;
        $previousOrderStateID = self::getPreviousOrderStateID($this->order->ID);

        if ($isNew) {
            $this->Date = date('Y-m-d');
            $this->Time = date('H:i');
        }

        if (UserAdminSession::getCurrentUserID() && !$this->User_ID) {
            $this->User_ID = UserAdminSession::getCurrentUserID();
        }

        parent::save($conn);

        if ( $isNew ) {
            $this->order->OrderStateType_ID = $this->OrderStateType_ID;
            $this->order->save();
            $invoice = null;
            
            if ($previousOrderStateID!= OrderStateType::ID_STATE_CANCEL && $this->OrderStateType_ID == OrderStateType::ID_STATE_CANCEL ) {
                Admin_Model_Product::updateStockAfterOrderCancel($this->order);
            }

            if($previousOrderStateID == OrderStateType::ID_STATE_CANCEL && $this->OrderStateType_ID != OrderStateType::ID_STATE_CANCEL) {
                Admin_Model_Product::updateStockAfterOrderRestore($this->order);
            }

            if ($this->OrderStateType_ID == OrderStateType::ID_STATE_DISTRIBUTED && $this->order->DateShipmentTransit == null) {
                $this->order->DateShipmentTransit = date('Y-m-d');
            }

            if ($this->OrderStateType_ID == OrderStateType::ID_STATE_FINISH && $this->order->DateShipped == null) {
                $this->order->DateShipped = date('Y-m-d');
            }

            $this->order->save();

            if ( $this->orderStateType->SendEmail )
                EmailFactory::sendOrderState($this, $invoice);
        }
    }

    /**
     * @param int $orderID
     * @param int $orderStateTypeID
     * @param string|null $userName
     * @return Admin_Model_OrderState
     */
    public static function createOrderState(int $orderID, int $orderStateTypeID, ?string $userName = null): Admin_Model_OrderState {
        $orderState = new Admin_Model_OrderState();
        $orderState->Order_ID = $orderID;
        $orderState->OrderStateType_ID = $orderStateTypeID;
        $orderState->UserName = $userName;
        $orderState->save();

        return $orderState;
    }

    private static function getPreviousOrderStateID($orderID)
    {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_OrderState');
        $query->where('Order_ID=?', $orderID);
        $query->addOrderBy('ID DESC');
        $query->limit(1);
        return $query->fetchOne()? $query->fetchOne()->OrderStateType_ID:null;
    }

}
